local ro = require(script.Parent.PropMarkers.Children)
local qL = require(script.Parent.ElementKind)
local rc = require(script.Parent.Logging)
local pS = require(script.Parent.Type)
local pT = require(script.Parent.GlobalConfig).get()
local sh = [[
The prop `Roact.Children` was defined but was overriden by the third parameter to createElement!
This can happen when a component passes props through to a child element but also uses the `children` argument:

	Roact.createElement("Frame", passedProps, {
		child = ...
	})

Instead, consider using a utility function to merge tables of children together:

	local children = mergeTables(passedProps[Roact.Children], {
		child = ...
	})

	local fullProps = mergeTables(passedProps, {
		[Roact.Children] = children
	})

	Roact.createElement("Frame", fullProps)]]
local function si(qO, l2, be)
	if pT.typeChecks then
		assert(qO ~= nil, "`component` is required")
		assert(typeof(l2) == "table" or l2 == nil, "`props` must be a table or nil")
		assert(typeof(be) == "table" or be == nil, "`children` must be a table or nil")
	end
	if l2 == nil then
		l2 = {}
	end
	if be ~= nil then
		if l2[ro] ~= nil then
			rc.warnOnce(sh)
		end
		l2[ro] = be
	end
	local sj = qL.fromComponent(qO)
	local rS = { [pS] = pS.Element, [qL] = sj, component = qO, props = l2 }
	if pT.elementTracing then
		rS.source = debug.traceback("", 2):sub(2)
	end
	return rS
end
return si
